407	localparam SG_STATE_IDLE = 2'b00;
408	localparam SG_STATE_PEND = 2'b01;
409	localparam SG_STATE_BUSY = 2'b10;
410	localparam SG_STATE_DONE = 2'b11;
411	
412	//## fsm (1) com block
413	
414	always @(
415	  cur_state
416	  or reg2dp_op_en
417	  or need_pending
418	  or pending_done
419	  or layer_done
420	  or fifo_is_clear
421	  or pkg_vld
422	  or dp2reg_done
423	  ) begin
424	  nxt_state = cur_state;
425	  begin
426	    casez (cur_state)
427	      SG_STATE_IDLE: begin
428	        if ((reg2dp_op_en & need_pending)) begin
429	          nxt_state = SG_STATE_PEND; 
430	        end
431	        `ifndef SYNTHESIS
432	        // VCS coverage off
433	        else if (((reg2dp_op_en & need_pending)) === 1'bx) begin
434	          nxt_state = 'bx;
435	        end
436	        // VCS coverage on
437	        `endif
438	        else if (reg2dp_op_en) begin
439	          nxt_state = SG_STATE_BUSY; 
440	        end
441	        `ifndef SYNTHESIS
442	        // VCS coverage off
443	        else if ((reg2dp_op_en) === 1'bx) begin
444	          nxt_state = 'bx;
445	        end
446	        // VCS coverage on
447	        `endif
448	      end
449	      SG_STATE_PEND: begin
450	        if (pending_done) begin
451	          nxt_state = SG_STATE_BUSY; 
452	        end
453	        `ifndef SYNTHESIS
454	        // VCS coverage off
455	        else if ((pending_done) === 1'bx) begin
456	          nxt_state = 'bx;
457	        end
458	        // VCS coverage on
459	        `endif
460	      end
461	      SG_STATE_BUSY: begin
462	        if (layer_done & fifo_is_clear & ~pkg_vld) begin
463	          nxt_state = SG_STATE_DONE; 
464	        end
465	        `ifndef SYNTHESIS
466	        // VCS coverage off
467	        else if ((layer_done & fifo_is_clear & ~pkg_vld) === 1'bx) begin
468	          nxt_state = 'bx;
469	        end
470	        // VCS coverage on
471	        `endif
472	      end
473	      SG_STATE_DONE: begin
474	        if (dp2reg_done) begin
475	          nxt_state = SG_STATE_IDLE; 
476	        end
477	        `ifndef SYNTHESIS
478	        // VCS coverage off
479	        else if ((dp2reg_done) === 1'bx) begin
480	          nxt_state = 'bx;
481	        end
482	        // VCS coverage on
483	        `endif
484	      end
485	      // VCS coverage off
486	      default: begin
487	        nxt_state = SG_STATE_IDLE; 
488	        `ifndef SYNTHESIS
489	        nxt_state = {2{1'bx}};
490	        `endif
491	      end
492	      // VCS coverage on
493	    endcase
494	  end
495	end
